export default function CustomproductDescripiton() {
  const { handles } = useCssHandles(CSS_HANDLES)
  const { product } = useProduct() as ProductContextState

  console.log(product)

  return (
    <section className={handles.customProductDescription}>
      <h4 className={handles.customProductDescriptionHeader}>Descrição</h4>
      <div
        className={handles.customProductDescriptionContent}
        dangerouslySetInnerHTML={{ __html: product?.description ?? '' }}
      />
      <h4
        className={applyModifiers(
          handles.customProductDescriptionHeader,
          'cuidados'
        )}
      >
        Cuidados
      </h4>
      <div className={handles.customProductDescriptionCuidados}>
        {cuidados.map((cuidado, index) => (
          <div key={index} className={handles.customProductDescriptionCuidado}>
            {cuidado.icon}
            <p className={handles.customProductDescriptionCuidadoTitle}>
              {cuidado.title}
            </p>
          </div>
        ))}
      </div>
    </section>
  )
}
